  <line x1="20" y1="100" x2="20" y2="350" stroke="#3f3f46" stroke-dasharray="3,3"/>
  <line x1="130" y1="100" x2="130" y2="350" stroke="#3f3f46" stroke-dasharray="3,3"/>
  <line x1="240" y1="100" x2="240" y2="350" stroke="#3f3f46" stroke-dasharray="3,3"/>
